#include<bits/stdc++.h>
using namespace std;
bool prime[100000001];
int c[100000001];
int main(){
	int n,q,s,cnt;
	cin>>n>>q;
	prime[1]=1;
	for(int i=2;i*i<=n;i++){
		if(prime[i]==false){
			for(int j=i;j*i<=n;j++){
				prime[j*i]=true;
			}
		}
	}
	for(int i=1;i<=n;i++){
		if(prime[i]==false){
			c[++cnt]=i;
		}
	}
	for(int i=1;i<=q;i++){
		cin>>s;
		cout<<c[s]<<"\n";
	}
	return 0;
}
